export interface Question {
  id: string;
  examPage?: number;
  examPageEnd?: number;
  stimulusPage?: number;
  examFile?: string;
  examImages?: string[];
  year: number;
  questionNumber: string;
  section: "I" | "II";
  type: "mc" | "short_answer" | "extended_response";
  marks: number;
  module: string;
  moduleContent: string;
  syllabusOutcomes: string[];
  questionText: string;
  options?: Record<string, string>;
  correctAnswer?: string;
  markingCriteria: string;
  sampleAnswer: string;
  hasImage: boolean;
  imageDescription?: string;
  parts?: { label: string; marks: number }[];
  tableConfig?: {
    columns: string[];
    rows: string[];
    prefilled?: Record<string, string>; // "row,col" -> value for read-only cells
    forPart?: string; // e.g. "(b)" — table replaces this part's textarea
  };
  graphConfig?: {
    xAxis: { label: string; min: number; max: number; step: number; ticks?: number[] };
    yAxis: { label: string; min: number; max: number; step: number; inverted?: boolean };
    series: { name: string; color: string; symbol: "circle" | "cross" }[];
    showLineOfBestFit?: boolean;
    forPart?: string; // which part this graph replaces
  };
}

